form:Form.form:Scripts:
		function sendReqAsync(content, callBack) {
    var msg;
    var objDoc;

    if (content == null)
        content = "";

    msg = "<http-envelope service='ProxyEngine' request='send' user-token='" + g_strToken + "'>" + content + "</http-envelope>";

    var hr = getHR();                 
    hr.open("POST", g_location + "ProxyEngine.aspx", true);
    hr.onreadystatechange = function() 
    { 
      //Resultado
      if (hr.readyState == 4) 
      {
        if (hr.status == 200) 
        {
            try 
            {
              objDoc = createDoc(hr.responseText);
            } catch (e) 
            {
              alert("sendReqAsync(): " + e.number + "  " + e.description);
					  enable_buttons();
				    return;
            }

            //Envia el resultado
            if (callBack)
              callBack(objDoc);
        } else 
        {
          alert("sendReqAsync(): ERROR " + hr.status);
			  enable_buttons();
		    return;
        }
      }
    };

    hr.send(msg);
}


function SQLGetAsync(qry, param, callBack) 
{                              
	sendReqAsync("<content-send SrvName=\"xquery\" Request=\"get-sql\" ><qry:declare xmlns:qry=\"nomad_engine.form\">"+param+"</qry:declare>"+qry+"</content-send>", function(doc) { 

    //Switchea las posibles respuestas
    strService  = doc.documentElement.attributes.getNamedItem("service").value;
    strResponse = doc.documentElement.attributes.getNamedItem("response").value;

    switch (strResponse) 
    {
        case "send-response":
          var eleResponse = doc.documentElement.childNodes.item(0);
          objResult = new NomadProxyResponse(eleResponse.attributes.getNamedItem("service").value, eleResponse.attributes.getNamedItem("response").value, eleResponse.childNodes.item(0));

				//Resultado                                       
          //Envia el resultado
          if (callBack)
            callBack(objResult.Message());
		    return;

        default:
          alert("invalid server reply, "+strResponse);
			  enable_buttons();
		    return;
    }
});
}



