//Generar la lista de search
function Searchs()
{      
	Ctrl("search1").SetXValue("");
	Ctrl("search2").SetXValue("");
	Ctrl("search3").SetXValue("");
	Ctrl("search4").SetXValue("");
	Ctrl("search5").SetXValue("");

  var count = 0;
  var Last = "";

  var nombre=Ctrl('buscar').GetXValue().toUpperCase();
  for(var t=0; t<nombre.length; t++)
  {
    if (nombre.substr(t,1)>='A' && nombre.substr(t,1)<='Z')
    	Last += nombre.substr(t,1);
    else if (nombre.substr(t,1)>='0' && nombre.substr(t,1)<='9')
    	Last += nombre.substr(t,1);
    else if (nombre.substr(t,1)=='_')
    	Last += nombre.substr(t,1);
   	else
  	if (Last != "")
  	{
  		count++;
		if (Ctrl("search"+count)) Ctrl("search"+count).SetXValue(Last);
		Last="";
  	}
  }               

if (Last != "")
{
	count++; 
	if (Ctrl("search"+count)) Ctrl("search"+count).SetXValue(Last);
	Last="";
}
}


function exec_qry_async(callBackFunction)
{
  var np = GetProxy();
  var qry = Ctrl("main").getResource("qry_ids");	
  var qryMembers = qry.split("##");
  var qryMembers = qryMembers[1].split(",");
  var qryExt = null;        

	//Lista de searchs...            
  Searchs();

  var MyMSG = PREV_exec_qry();
  if (MyMSG)
  {
    alert(MyMSG);               
		enable_buttons();
    return;
  }

	//Validaciones Basicas
  var nmdDATA=new NomadXML("PARAM");
  for (var i=0; i<qryMembers.length; i++)
  {     
    if(Ctrl(qryMembers[i]))
    {
      if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
      {
        alert("El valor es requerido");
        Ctrl(qryMembers[i]).SetFocus();
		  enable_buttons();
	    return;
      }
      nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
    }
  }                  

	//Consulta principal
	SQLGetAsync(
		qry, 
		nmdDATA.ToString(), 
		function(result) 
		{ 
		  var resultArray = STR2array(result);

	  	POST_exec_qry(resultArray);
	  	if (callBackFunction)
	  		callBackFunction(resultArray);
		} 
	);
}



//Transaforma un XML(tipo STRING) en ARRAY
function STR2array(str)
{
  var arr = new Array();

  var cur = 0, pos;
  while(true) 
  {
    pos = str.indexOf("id=\"", cur);
    if (pos < 0) break;

    cur = pos+4;
    pos = str.indexOf("\"", cur);
    arr.push(str.substr(cur, pos-cur));
    cur = pos+1;
  }

  return arr;
}


//Function para activar y desactivar Botones
function enable_chk_buttons()
{ 
	CtrlEnabled("lst_unmark", Ctrl("chk").CountRow()==0?false:true);
	CtrlEnabled("ACCEPT", Ctrl("chk").CountRow()==0?false:true);
}

function enable_buttons(msg)
{                      
	if (Ctrl("lst").SetMessage) Ctrl("lst").SetMessage(msg);
	CtrlEnabled("lst", msg ? false : true);
	enable_chk_buttons();

	CtrlEnabled("buscar", true);

	enable_custom_buttons();
	loadingMessage(false, null);
	formEnabled = true;
}

function enable_custom_buttons()
{
}

//Function para activar y desactivar Botones
function disable_buttons(msg)
{                           
	loadingMessage(true, msg);
	CtrlEnabled("lst", false);
	CtrlEnabled("buscar", false);
	CtrlEnabled("ACCEPT", false);
	if (Ctrl("lst").SetMessage) Ctrl("lst").SetMessage(msg);

	disable_custom_buttons();
	formEnabled = false;     
}

function disable_custom_buttons()
{
}


function internalLoad(callback)    
{       
	//Mensaje
	disable_buttons("Cargando la lista...");

	//Optener el resultado
  exec_qry_async(
	  function(auxArr) 
	  {
		  if (auxArr==null) return;


		  //Valido
		  if (auxArr.length > 1000)
		  {                         
		  	refreshList("Afinar la busqueda.");
			  return;
		  }       

		  arrLST = auxArr; 

		  //Quita los elementos seleccionados
		  Ctrl("lst").SetXValue("");
		  Ctrl("chk").DelAllRow();
		  refreshList();    

		  //llamada a la funcion de callback
		  if (callback) 
		  	callback();

	  }
  );
}

function load() { internalLoad(null); }

function unmark()
{
  Ctrl("lst").SetXValue("");
  Ctrl("chk").DelAllRow();
  refreshList();
}

function ACCEPT()
{                         
	var ids ="";
	var sep ="";


  //Valores Iniciales
  for (var t=0; t<Ctrl("chk").CountRow(); t++)
  {
    ids += sep + Ctrl("chk").GetRow(t).GetAttr("ID"); 
    sep=",";
  } 

	Ctrl("ids").SetXValue(ids);
	Ctrl("main").DoEvent("ACCEPT");
}
